---
import type { HTMLAttributes } from "astro/types"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"header"> & VariantProps<typeof variants>

const variants = cva("relative z-50 flex w-full items-center gap-4 py-2", {
  variants: {
    variant: {
      default: "",
      floating:
        "bg-background mx-auto my-2 w-[calc(100%-2rem)] max-w-[calc(var(--container,1280px)-2rem)] overflow-hidden rounded-lg border shadow-sm",
    },
  },
  defaultVariants: {
    variant: "default",
  },
})

const { class: className, variant, ...props } = Astro.props
---

<header
  class={cn(variants({ variant }), className)}
  data-slot="header"
  data-variant={variant}
  {...props}
>
  <slot />
</header>
